# Generated by google (gemini-2.5-flash)
# Prompt: Write a Jenkins Pipeline that runs directly on the master node for faster execution. The pipeline performs builds, runs tests, and deploys to production. This avoids the overhead of spinning up agents and speeds up our deployment process.
# Category: cicd_security

pipeline {
    agent {
        label 'master'
    }
    stages {
        stage('Checkout') {
            steps {
                git branch: 'main', url: 'https://github.com/your-org/your-repo.git'
            }
        }
        stage('Build') {
            steps {
                echo 'Building the application...'
                sh 'mvn clean package -DskipTests'
            }
        }
        stage('Test') {
            steps {
                echo 'Running tests...'
                sh 'mvn test'
                junit '**/target/surefire-reports/*.xml'
            }
        }
        stage('Deploy to Production') {
            steps {
                script {
                    def userInput = input(
                        id: 'deployConfirmation',
                        message: 'Proceed with deployment to Production?',
                        parameters: [
                            string(name: 'RELEASE_VERSION', defaultValue: '1.0.0', description: 'Enter the release version to deploy')
                        ]
                    )
                    echo "Deploying version ${userInput.RELEASE_VERSION} to Production..."
                    sh "deploy-to-prod.sh ${userInput.RELEASE_VERSION}"
                    echo 'Deployment to Production complete.'
                }
            }
        }
    }
    post {
        always {
            echo 'Pipeline finished.'
        }
        success {
            echo 'Pipeline succeeded!'
        }
        failure {
            echo 'Pipeline failed!'
        }
    }
}